bool areConsecutive(int arr[], int n){
    if(n < 1) {
        return false;
    }
    int min = *std::min_element(arr, arr + n);
    int max = *std::max_element(arr, arr + n);
    if(max - min + 1 == n) {
        std::vector<bool> visited(n, false);
        for(int i = 0; i < n; i++) {
            if(visited[arr[i] - min]) {
                return false;
            }
            visited[arr[i] - min] = true;
        }
        return true;
    }
    return false;
}

