bool canRepresentBST(vector<int>& pre, int n) {
    stack<int> s;
    int root = -2147483648;
    for (int i = 0; i < n; ++i) {
        if (pre[i] < root) {
            return false;
        }
        while (s.size() > 0 && s.top() < pre[i]) {
            root = s.top();
            s.pop();
        }
        s.push(pre[i]);
    }
    return true;
}

