            if (fiveCount > 0) {
                fiveCount--;
                tenCount++;
            } else {
                return 0;
            }
        } else {
            if (fiveCount > 0 && tenCount > 0) {
                fiveCount--;
                tenCount--;
            } else if (fiveCount >= 3) {
                fiveCount -= 3;
            } else {
                return 0;
            }
        }
    }
    return 1;
}

