    for (i = 1; i < n; i++) {
        if (arr[i - 1] >= arr[i]) {
            break;
        } else {
            if (i == n) {
                return true;
            }
        }
    }
    int j = i;
    i += 1;
    while (arr[j] < arr[j - 1]) {
        if (i > 1 and arr[j] < arr[i - 2]) {
            return false;
        }
        j += 1;
    }
    if (j == n) {
        return true;
    }
    int k = j;
    if (arr[k] < arr[i - 1]) {
        return false;
    }
    while (k > 1 and k < n) {
