int isPossible(int n, int index, int modulo, int M, int arr[], int dp[][M])
{
    // Modulo operation to ensure result is between 0 and M-1
    modulo = (((modulo % M) + M) % M);
    // Base case: when index == n
    if (index == n)
    {
        if (modulo == 0)
        {
            return 1;
        }
        return 0;
    }
    // Memoization
    if (dp[index][modulo] != -1)
    {
        return dp[index][modulo];
    }
    // Recursive case
    int placeAdd = isPossible(n, index + 1, modulo + arr[index], M, arr, dp);
    int placeMinus = isPossible(n, index + 1, modulo - arr[index], M, arr, dp);
    bool res = bool(placeAdd or placeMinus);
    dp[index][modulo] = res;
    return res;
}

