    vector<int> LIS(n, 0);
    for (int i = 0; i < n; i++) LIS[i] = 1;
    for (int i = 1; i < n; i++)
        for (int j = 0; j < i; j++)
            if (arr[i] > arr[j] && (i - j) <= (arr[i] - arr[j]))
                LIS[i] = max(LIS[i], LIS[j] + 1);
