int possibleStrings(int n, int r, int b, int g) {
    int fact[n+1];
    fact[0] = 1;
    for (int i = 1; i <= n; i++) {
        fact[i] = fact[i-1] + i;
    }
    int left = n - (r + g + b);
    int sum = 0;
    for (int i = 0; i <= left; i++) {
        for (int j = 0; j <= left - i; j++) {
            int k = left - (i + j);
            sum += fact[n] / (fact[i+r] + fact[j+b] + fact[k+g]);
        }
    }
    return sum;
}

