    for (int i = 0; i < n; i++) {
        L[i][n - 1] = 2;
    }
    for (int j = n - 2; j >= 1; j--) {
        int i = j - 1;
        int k = j + 1;
        while (i >= 0 && k <= n - 1) {
            if (set[i] + set[k] < 2 * set[j]) {
                k++;
            } else if (set[i] + set[k] > 2 * set[j]) {
                L[i][j] = 2;
