    for (int i = 0; i < n - 1; i++) {
        int pos = i;
        for (int j = i + 1; j < n; j++) {
            if (j - i > k) break;
            if (arr[j] < arr[pos]) {
                pos = j;
            }
        }
        for (int j = pos; j > i; j--) {
            int temp = arr[j];
