int MinimumCost(vector<int>& cost, int n, int W) {
    vector<int> val;
    vector<int> wt;
    int size = 0;
    for (int i = 0; i < n; i++) {
        if (cost[i] != -1) {
            val.push_back(cost[i]);
            wt.push_back(i + 1);
            size += 1;
        }
    }
    n = size;
    vector<vector<int>> min_cost(n + 1, vector<int>(W + 1, 0));
    for (int i = 0; i < W + 1; i++) {
        min_cost[0][i] = INT_MAX;
    }
