        min_cost[i][0] = 0;
    }
    for (int i = 1; i < n + 1; i++) {
        for (int j = 1; j < W + 1; j++) {
            if (wt[i - 1] > j) {
                min_cost[i][j] = min_cost[i - 1][j];
            } else {
                min_cost[i][j] = min(min_cost[i - 1][j], min_cost[i][j - wt[i - 1]] + val[i - 1]);
            }
        }
    }
